noncompliant:
// Using predictable salt
string salt = "fixed_salt_value";
using (var pbkdf2 = new Rfc2898DeriveBytes(password, Encoding.UTF8.GetBytes(salt), 1000))
{
    byte[] hash = pbkdf2.GetBytes(32);
}

// No salt
string hash = BCrypt.Net.BCrypt.HashPassword(password);

compliant:
// Generate cryptographically random salt
byte[] salt = new byte[32];
using (var rng = RandomNumberGenerator.Create())
{
    rng.GetBytes(salt);
}

using (var pbkdf2 = new Rfc2898DeriveBytes(password, salt, 100000))
{
    byte[] hash = pbkdf2.GetBytes(32);
}

// Using bcrypt with automatic salt generation
string hash = BCrypt.Net.BCrypt.HashPassword(password, 12);
